"use client";

import { type ComponentType, FormEvent, useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useSearchParams } from "next/navigation";

import { AdminCard, AdminPageIntro, PrimaryActionButton, SecondaryButton } from "../_components/admin-design-system";
import { DEFAULT_PAGE_SIZE, Pagination } from "../_components/Pagination";
import { fetchAdministratorJson } from "@/lib/admin-api-client";
import { Skeleton, SkeletonTable } from "@/components/ui/Skeleton";
import { PlacesAddressInput, type SelectedPlace } from "@/components/routes/PlacesAddressInput";
import { useNotify } from "@/components/ui/ToastProvider";
import { findRelevantAssignment, isVehicleOperational } from "@/lib/operations";
import { AppIcons } from "@/config/icons";

type DeliveryStatus = "pending" | "assigned" | "in_transit" | "delivered" | "delayed" | "failed" | "returned";
type DeliveryPriority = "low" | "normal" | "high" | "urgent";
type DeliveryRow = { delivery_id: string; delivery_number: string | null; customer_name: string | null; customer_phone: string | null; pickup_address: string | null; pickup_place_id: string | null; pickup_latitude: number | string | null; pickup_longitude: number | string | null; delivery_address: string | null; delivery_place_id: string | null; delivery_latitude: number | string | null; delivery_longitude: number | string | null; assigned_driver_id: string | null; assigned_vehicle_id: string | null; status: string | null; priority: string | null; notes: string | null; created_by: string | null; created_at: string | null; updated_at: string | null };
type DriverRow = { driver_id: string; user_id: string | null; assigned_vehicle_id: string | null; availability: string | null };
type ProfileRow = { profile_id: string; first_name: string | null; last_name: string | null; email: string | null; phone: string | null; role: string | null; is_active: boolean | null };
type VehicleRow = { vehicle_id: string; vehicle_number: string | null; license_plate: string | null; make: string | null; model: string | null; status: string | null };
type ScheduleRow = { schedule_id: string; driver_id: string | null; vehicle_id: string | null; shift_name: string | null; shift_type: string | null; start_time: string | null; end_time: string | null; status: string | null };
type RouteRow = { route_id: string; delivery_id: string | null; origin: string | null; destination: string | null; origin_name: string | null; origin_address: string | null; destination_name: string | null; destination_address: string | null; estimated_distance_km: number | string | null; estimated_duration_minutes: number | string | null; actual_distance_km: number | string | null; actual_duration_minutes: number | string | null; maps_url: string | null; route_provider: string | null; sequence_order: number | null; created_at: string | null };
type HistoryRow = Record<string, unknown>;
type ApiData = { deliveries: DeliveryRow[]; drivers: DriverRow[]; profiles: ProfileRow[]; vehicles: VehicleRow[]; schedules: ScheduleRow[]; routes: RouteRow[]; history: HistoryRow[] };
type DriverOption = { id: string; name: string; phone: string; email: string; detail: string; availability: string; vehicleId: string; vehicleName: string; active: boolean; scheduleId: string };
type VehicleOption = { id: string; name: string; detail: string; status: string };
type DeliveryRecord = { id: string; number: string; customerName: string; customerPhone: string; pickupAddress: string; pickupPlaceId: string; pickupLatitude: number | null; pickupLongitude: number | null; deliveryAddress: string; deliveryPlaceId: string; deliveryLatitude: number | null; deliveryLongitude: number | null; driverId: string; driverName: string; driverPhone: string; driverEmail: string; driverDetail: string; vehicleId: string; vehicleName: string; vehicleNumber: string; vehicleMakeModel: string; vehiclePlate: string; status: DeliveryStatus; priority: DeliveryPriority; notes: string; createdBy: string; createdAt: string | null; updatedAt: string | null; schedule: ScheduleRow | null; route: RouteRow | null; history: HistoryRow[] };
type FormState = { deliveryNumber: string; customerName: string; customerPhone: string; pickupAddress: string; pickupPlaceId: string; pickupLatitude: string; pickupLongitude: string; deliveryAddress: string; deliveryPlaceId: string; deliveryLatitude: string; deliveryLongitude: string; driverId: string; vehicleId: string; status: DeliveryStatus; priority: DeliveryPriority; notes: string };

const statuses: Array<{ value: DeliveryStatus; label: string }> = [{ value: "pending", label: "Pending" }, { value: "assigned", label: "Assigned" }, { value: "in_transit", label: "In Transit" }, { value: "delivered", label: "Delivered" }, { value: "delayed", label: "Delayed" }, { value: "failed", label: "Failed" }, { value: "returned", label: "Returned" }];
const priorities: Array<{ value: DeliveryPriority; label: string }> = [{ value: "low", label: "Low" }, { value: "normal", label: "Normal" }, { value: "high", label: "High" }, { value: "urgent", label: "Urgent" }];
const emptyForm: FormState = { deliveryNumber: "", customerName: "", customerPhone: "", pickupAddress: "", pickupPlaceId: "", pickupLatitude: "", pickupLongitude: "", deliveryAddress: "", deliveryPlaceId: "", deliveryLatitude: "", deliveryLongitude: "", driverId: "", vehicleId: "", status: "pending", priority: "normal", notes: "" };

function normalizeStatus(value: string | null): DeliveryStatus { const normalized = (value ?? "pending").toLowerCase().replaceAll(" ", "_"); return statuses.some((item) => item.value === normalized) ? normalized as DeliveryStatus : "pending"; }
function normalizePriority(value: string | null): DeliveryPriority { const normalized = (value ?? "normal").toLowerCase(); return priorities.some((item) => item.value === normalized) ? normalized as DeliveryPriority : "normal"; }
function profileName(profile?: ProfileRow) { return [profile?.first_name, profile?.last_name].filter(Boolean).join(" ") || profile?.email || "Unnamed driver"; }
function vehicleName(vehicle?: VehicleRow) { return [vehicle?.vehicle_number, [vehicle?.make, vehicle?.model].filter(Boolean).join(" ")].filter(Boolean).join(" / ") || vehicle?.license_plate || "Unnamed vehicle"; }
function vehicleDetail(vehicle?: VehicleRow) { return [vehicle?.license_plate, vehicle?.status?.replaceAll("_", " ")].filter(Boolean).join(" / "); }
function formatPhone(value: string) { const digits = value.replace(/\D/g, ""); if (digits.length === 10) return `(${digits.slice(0, 3)}) ${digits.slice(3, 6)}-${digits.slice(6)}`; if (digits.length === 11 && digits.startsWith("1")) return `+1 (${digits.slice(1, 4)}) ${digits.slice(4, 7)}-${digits.slice(7)}`; return value || "Not provided"; }
function routeDistance(route: RouteRow | null) { const value = route?.actual_distance_km ?? route?.estimated_distance_km; return value ? `${value} km` : "Not calculated"; }
function routeDuration(route: RouteRow | null) { const value = route?.actual_duration_minutes ?? route?.estimated_duration_minutes; return value ? `${value} min` : "Not calculated"; }
function shortLocation(address: string) { const parts = address.split(",").map((part) => part.trim()).filter(Boolean); const locality = parts.length > 1 ? parts[parts.length > 3 ? parts.length - 3 : 1] : parts[0]; return locality?.replace(/^\d+\s+/, "").replace(/\b[A-Z]{2}\s+\d{5}(?:-\d{4})?$/i, "").trim() || "Unknown"; }
function routeLocations(delivery: DeliveryRecord) { return { from: shortLocation(delivery.pickupAddress), to: shortLocation(delivery.deliveryAddress) }; }
function tableEta(route: RouteRow | null) { const value = route?.actual_duration_minutes ?? route?.estimated_duration_minutes; return value ? `${value} min` : "ETA unavailable"; }
function RouteSummary({ delivery }: { delivery: DeliveryRecord }) { const { from, to } = routeLocations(delivery); return <span className="inline-flex min-w-0 max-w-full items-center gap-2"><span className="truncate">{from}</span><span aria-hidden className="grid h-5 w-5 shrink-0 place-items-center rounded-full bg-purple-50 text-[11px] font-bold text-purple-600 ring-1 ring-purple-100">→</span><span className="truncate">{to}</span></span>; }
function formatDate(value: string | null) { if (!value) return "Not recorded"; const date = new Date(value); return Number.isNaN(date.getTime()) ? "Not recorded" : new Intl.DateTimeFormat("en", { month: "short", day: "numeric", year: "numeric" }).format(date); }
function formatDateTime(value: string | null) { if (!value) return "Not recorded"; const date = new Date(value); return Number.isNaN(date.getTime()) ? "Not recorded" : new Intl.DateTimeFormat("en", { month: "short", day: "numeric", year: "numeric", hour: "numeric", minute: "2-digit" }).format(date); }
function statusLabel(status: DeliveryStatus) { return statuses.find((item) => item.value === status)?.label ?? "Pending"; }
function priorityLabel(priority: DeliveryPriority) { return priorities.find((item) => item.value === priority)?.label ?? "Normal"; }
function historyValue(row: HistoryRow, keys: string[]) { for (const key of keys) if (typeof row[key] === "string") return row[key] as string; return null; }
function isDeliveryHistory(row: HistoryRow, deliveryId: string) { return historyValue(row, ["delivery_id"]) === deliveryId; }
function numberValue(value: number | string | null) { const number = Number(value); return value === null || value === "" || !Number.isFinite(number) ? null : number; }

function StatusBadge({ status }: { status: DeliveryStatus }) { const tone = status === "delivered" ? "bg-emerald-50 text-emerald-700" : status === "in_transit" ? "bg-blue-50 text-blue-700" : status === "assigned" ? "bg-purple-50 text-purple-700" : status === "delayed" ? "bg-amber-50 text-amber-700" : status === "failed" ? "bg-red-50 text-red-700" : status === "returned" ? "bg-orange-50 text-orange-700" : "bg-slate-100 text-slate-600"; return <span className={`inline-flex rounded-full px-2.5 py-1 text-xs font-semibold ${tone}`}>{statusLabel(status)}</span>; }
function PriorityBadge({ priority }: { priority: DeliveryPriority }) { const tone = priority === "urgent" ? "bg-red-50 text-red-700" : priority === "high" ? "bg-orange-50 text-orange-700" : priority === "low" ? "bg-slate-100 text-slate-600" : "bg-blue-50 text-blue-700"; return <span className={`inline-flex rounded-full px-2.5 py-1 text-xs font-semibold ${tone}`}>{priorityLabel(priority)}</span>; }
function KpiCard({ label, value, detail, accent = false, isLoading = false }: { label: string; value: number; detail: string; accent?: boolean; isLoading?: boolean }) { return <div className={`rounded-[20px] border p-5 shadow-sm ${accent ? "border-[#172f3a] bg-[#172f3a] text-white" : "border-slate-100 bg-white text-[#17232b]"}`}>{isLoading ? <><Skeleton className="h-3 w-24" rounded="rounded-full" /><Skeleton className="mt-4 h-9 w-20" rounded="rounded-full" /><Skeleton className="mt-2 h-3 w-32" rounded="rounded-full" /></> : <><p className={accent ? "text-xs text-slate-300" : "text-xs text-slate-500"}>{label}</p><p className="mt-4 text-3xl font-semibold tracking-[-0.03em]">{value}</p><p className={accent ? "mt-1 text-xs text-slate-400" : "mt-1 text-xs text-slate-400"}>{detail}</p></>}</div>; }

function SearchableSelect({ label, value, placeholder, options, onChange }: { label: string; value: string; placeholder: string; options: Array<{ id: string; label: string; detail: string }>; onChange: (value: string) => void }) {
  const [open, setOpen] = useState(false); const [query, setQuery] = useState(""); const ref = useRef<HTMLDivElement>(null); const selected = options.find((option) => option.id === value);
  useEffect(() => { function close(event: MouseEvent) { if (!ref.current?.contains(event.target as Node)) setOpen(false); } document.addEventListener("mousedown", close); return () => document.removeEventListener("mousedown", close); }, []);
  const filtered = options.filter((option) => `${option.label} ${option.detail}`.toLowerCase().includes(query.toLowerCase()));
  return <div className="relative" ref={ref}><label className="text-sm font-medium text-slate-600">{label}</label><button className="mt-2 flex h-11 w-full items-center justify-between rounded-xl border border-slate-200 bg-slate-50 px-4 text-left text-sm outline-none transition hover:border-purple-200 focus:border-purple-300 focus:ring-2 focus:ring-purple-100" onClick={() => { setOpen((current) => !current); setQuery(""); }} type="button"><span className={selected ? "truncate text-slate-800" : "truncate text-slate-400"}>{selected?.label ?? placeholder}</span><span className="text-slate-400">v</span></button>{open ? <div className="absolute z-30 mt-2 w-full rounded-2xl border border-slate-200 bg-white p-2 shadow-xl"><input autoFocus className="h-9 w-full rounded-xl border border-slate-200 bg-slate-50 px-3 text-sm outline-none focus:border-purple-300" onChange={(event) => setQuery(event.target.value)} placeholder={placeholder} value={query} /><div className="mt-2 max-h-48 overflow-y-auto"><button className="w-full rounded-xl px-3 py-2 text-left text-sm text-slate-500 hover:bg-slate-50" onClick={() => { onChange(""); setOpen(false); }} type="button">Unassigned</button>{filtered.map((option) => <button className="w-full rounded-xl px-3 py-2 text-left hover:bg-purple-50" key={option.id} onClick={() => { onChange(option.id); setOpen(false); }} type="button"><span className="block text-sm font-medium text-slate-800">{option.label}</span><span className="mt-0.5 block text-xs capitalize text-slate-400">{option.detail}</span></button>)}{filtered.length === 0 ? <p className="px-3 py-4 text-center text-xs text-slate-400">No matching records</p> : null}</div></div> : null}</div>;
}

function DeliveryModal({ form, editing, saving, error, drivers, vehicles, onChange, onPlace, onClose, onSubmit }: { form: FormState; editing: boolean; saving: boolean; error: string; drivers: DriverOption[]; vehicles: VehicleOption[]; onChange: (field: keyof FormState, value: string) => void; onPlace: (field: "pickupAddress" | "deliveryAddress", place: SelectedPlace) => void; onClose: () => void; onSubmit: (event: FormEvent<HTMLFormElement>) => void }) {
  useEffect(() => { const overflow = document.body.style.overflow; document.body.style.overflow = "hidden"; return () => { document.body.style.overflow = overflow; }; }, []);
  const input = "mt-2 h-11 w-full rounded-xl border border-slate-200 bg-slate-50 px-4 text-sm text-slate-900 outline-none transition focus:border-purple-300 focus:bg-white focus:ring-2 focus:ring-purple-100";
  const selectedVehicle = vehicles.find((vehicle) => vehicle.id === form.vehicleId); return <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/30 p-4 backdrop-blur-md" role="presentation" onClick={onClose}><div aria-modal="true" className="max-h-[92vh] w-full max-w-4xl overflow-hidden rounded-[24px] border border-white bg-white/95 p-1.5 shadow-2xl" onClick={(event) => event.stopPropagation()} role="dialog"><div className="user-modal-scrollbar max-h-[calc(92vh-0.75rem)] overflow-y-auto rounded-[19px] p-5 sm:p-6"><div className="flex items-start justify-between gap-4 border-b border-slate-100 pb-4"><div><h2 className="text-xl font-semibold text-slate-950">{editing ? "Edit Delivery" : "Create Delivery"}</h2><p className="mt-1 text-sm text-slate-500">Manage customer, route, assignment, status, and priority details.</p></div><button aria-label="Close delivery modal" className="grid h-9 w-9 place-items-center rounded-full border border-slate-200 text-slate-500 hover:bg-purple-50 hover:text-purple-700" disabled={saving} onClick={onClose} type="button">x</button></div><form className="mt-5" onSubmit={onSubmit}>{error ? <p className="mb-4 rounded-xl border border-red-100 bg-red-50 px-4 py-3 text-sm text-red-700">{error}</p> : null}<div className="grid gap-4 md:grid-cols-2"><label><span className="text-sm font-medium text-slate-600">Delivery Number</span><input className={input} onChange={(event) => onChange("deliveryNumber", event.target.value)} required value={form.deliveryNumber} /></label><label><span className="text-sm font-medium text-slate-600">Customer Name</span><input className={input} onChange={(event) => onChange("customerName", event.target.value)} required value={form.customerName} /></label><label><span className="text-sm font-medium text-slate-600">Customer Phone</span><input className={input} onChange={(event) => onChange("customerPhone", event.target.value)} type="tel" value={form.customerPhone} /></label><label><span className="text-sm font-medium text-slate-600">Status</span><select className={`${input} appearance-none`} onChange={(event) => onChange("status", event.target.value)} value={form.status}>{statuses.map((status) => <option key={status.value} value={status.value}>{status.label}</option>)}</select></label><div className="md:col-span-2"><PlacesAddressInput className={input} id="delivery-pickup-address" label="Pickup Address" onPlaceSelect={(place) => onPlace("pickupAddress", place)} onTextChange={(value) => onChange("pickupAddress", value)} required value={form.pickupAddress} /></div><div className="md:col-span-2"><PlacesAddressInput className={input} id="delivery-dropoff-address" label="Delivery Address" onPlaceSelect={(place) => onPlace("deliveryAddress", place)} onTextChange={(value) => onChange("deliveryAddress", value)} required value={form.deliveryAddress} /></div><SearchableSelect key={`driver-${form.driverId}`} label="Assigned Driver" onChange={(value) => { const driver = drivers.find((item) => item.id === value); onChange("driverId", value); onChange("vehicleId", driver?.vehicleId ?? ""); }} options={drivers.filter((driver) => driver.active && driver.availability !== "unavailable" && driver.vehicleId).map((driver) => ({ id: driver.id, label: driver.name, detail: driver.detail }))} placeholder="Search scheduled drivers" value={form.driverId} /><label><span className="text-sm font-medium text-slate-600">Assigned Vehicle</span><input className={input} readOnly value={selectedVehicle ? `${selectedVehicle.name} ${selectedVehicle.detail ? `- ${selectedVehicle.detail}` : ""}` : "Select a scheduled driver"} /></label><label><span className="text-sm font-medium text-slate-600">Priority</span><select className={`${input} appearance-none`} onChange={(event) => onChange("priority", event.target.value)} value={form.priority}>{priorities.map((priority) => <option key={priority.value} value={priority.value}>{priority.label}</option>)}</select></label><label className="md:col-span-2"><span className="text-sm font-medium text-slate-600">Notes</span><textarea className="mt-2 min-h-24 w-full rounded-xl border border-slate-200 bg-slate-50 px-4 py-3 text-sm outline-none transition focus:border-purple-300 focus:bg-white focus:ring-2 focus:ring-purple-100" onChange={(event) => onChange("notes", event.target.value)} value={form.notes} /></label></div><div className="mt-5 flex flex-col-reverse gap-3 border-t border-slate-100 pt-5 sm:flex-row sm:justify-end"><SecondaryButton disabled={saving} onClick={onClose} type="button">Cancel</SecondaryButton><PrimaryActionButton disabled={saving} type="submit">{saving ? "Saving..." : editing ? "Save Changes" : "Create Delivery"}</PrimaryActionButton></div></form></div></div></div>;
}

function DetailItem({ label, value, icon: Icon }: { label: string; value: string; icon?: ComponentType<{ size?: number; weight?: "regular" | "bold"; className?: string; "aria-hidden"?: boolean }> }) { return <div className="flex gap-3 rounded-2xl border border-purple-100/80 bg-white p-4 shadow-[0_1px_2px_rgba(15,23,42,0.04),0_10px_30px_rgba(139,92,246,0.06)]"><span className="mt-0.5 grid h-9 w-9 shrink-0 place-items-center rounded-xl bg-purple-50 text-purple-600 ring-1 ring-purple-100">{Icon ? <Icon aria-hidden size={17} weight="bold" /> : null}</span><div className="min-w-0"><p className="text-xs font-medium text-slate-400">{label}</p><p className="mt-1 break-words text-sm font-semibold leading-6 text-slate-800">{value}</p></div></div>; }

function DetailsModal({ delivery, onClose, onEdit, onDelete }: { delivery: DeliveryRecord; onClose: () => void; onEdit: () => void; onDelete: () => void }) {
  const CloseIcon = AppIcons.close; const EditIcon = AppIcons.edit; const MoreIcon = AppIcons.more; const DeleteIcon = AppIcons.delete; const CustomerIcon = AppIcons.customer; const PhoneIcon = AppIcons.phone; const PickupIcon = AppIcons.location; const DestinationIcon = AppIcons.navigation; const VehicleIcon = AppIcons.vehicles; const RouteIcon = AppIcons.map; const NotesIcon = AppIcons.clipboard; const ActivityIcon = AppIcons.activity;
  const scheduledTime = delivery.schedule ? `${formatDateTime(delivery.schedule.start_time)} - ${formatDateTime(delivery.schedule.end_time)}` : "No active schedule";
  const routeOrigin = delivery.route?.origin_name || delivery.route?.origin_address || delivery.route?.origin || delivery.pickupAddress;
  const routeDestination = delivery.route?.destination_name || delivery.route?.destination_address || delivery.route?.destination || delivery.deliveryAddress;
  const assignmentFields = [{ label: "Driver", value: delivery.driverName }, { label: "Phone", value: formatPhone(delivery.driverPhone) }, { label: "Email", value: delivery.driverEmail || "Not provided", wide: true, truncate: true }, { label: "Vehicle number", value: delivery.vehicleNumber || "Not assigned" }, { label: "Make/model", value: delivery.vehicleMakeModel || "Not recorded" }, { label: "License plate", value: delivery.vehiclePlate || "Not recorded" }, { label: "Shift name", value: delivery.schedule?.shift_name || "No active schedule" }, { label: "Scheduled date/time", value: scheduledTime, wide: true }];
  const cardClass = "rounded-[20px] border border-purple-100/80 bg-white p-5 shadow-[0_1px_2px_rgba(15,23,42,0.04),0_10px_30px_rgba(139,92,246,0.08)]";
  const accentCardClass = "rounded-[20px] border border-purple-100/80 bg-white p-5 shadow-[0_1px_2px_rgba(15,23,42,0.04),0_10px_30px_rgba(139,92,246,0.08)]";
  const summaryCellClass = "rounded-2xl border border-purple-100/70 bg-white px-3 py-2.5 shadow-[0_1px_2px_rgba(15,23,42,0.03),0_8px_22px_rgba(139,92,246,0.055)]";
  const secondaryPurpleButtonClass = "border-purple-200 bg-white text-purple-700 shadow-sm shadow-purple-100/60 hover:border-purple-300 hover:bg-purple-50 hover:text-purple-800 focus-visible:ring-purple-300";
  return <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-950/30 p-6 backdrop-blur-md" onClick={onClose} role="presentation"><div aria-modal="true" className="overflow-hidden rounded-[24px] border border-white bg-white/95 p-1.5 text-[#17232b] shadow-2xl shadow-purple-950/15 ring-1 ring-purple-100/70" onClick={(event) => event.stopPropagation()} role="dialog" style={{ width: "min(1080px, calc(100vw - 48px))", maxHeight: "calc(100vh - 48px)" }}><div className="flex max-h-[calc(100vh-60px)] flex-col overflow-hidden rounded-[19px]"><header className="sticky top-0 z-10 border-b border-slate-100 bg-white/95 px-5 py-4 backdrop-blur"><div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between"><div className="min-w-0"><div className="flex flex-wrap items-center gap-2"><h2 className="text-2xl font-semibold tracking-[-0.03em] text-slate-950">{delivery.number}</h2><StatusBadge status={delivery.status} /><PriorityBadge priority={delivery.priority} /></div><p className="mt-1 text-sm text-slate-500">Delivery details and operational activity.</p></div><div className="flex items-center gap-2"><PrimaryActionButton className="bg-purple-600 text-white shadow-sm shadow-purple-200 hover:bg-purple-700 focus-visible:ring-purple-300" onClick={onEdit} type="button"><EditIcon aria-hidden className="mr-2" size={15} weight="bold" />Edit</PrimaryActionButton><details className="relative"><summary aria-label="More delivery actions" className="grid h-10 w-10 cursor-pointer list-none place-items-center rounded-full border border-slate-200 text-slate-500 transition hover:border-purple-200 hover:bg-purple-50 hover:text-purple-700 [&::-webkit-details-marker]:hidden"><MoreIcon aria-hidden size={18} weight="bold" /></summary><div className="absolute right-0 top-12 z-20 w-44 rounded-2xl border border-slate-100 bg-white p-1.5 shadow-xl"><button className="flex w-full items-center gap-2 rounded-xl px-3 py-2 text-left text-sm font-semibold text-red-600 hover:bg-red-50" onClick={onDelete} type="button"><DeleteIcon aria-hidden size={15} weight="bold" />Delete delivery</button></div></details><button aria-label="Close delivery details" className="grid h-10 w-10 place-items-center rounded-full border border-slate-200 text-slate-500 transition hover:border-purple-200 hover:bg-purple-50 hover:text-purple-700" onClick={onClose} type="button"><CloseIcon aria-hidden size={16} weight="bold" /></button></div></div><div className="mt-4 grid gap-2 sm:grid-cols-2 lg:grid-cols-4">{[["Driver", delivery.driverName], ["Vehicle", delivery.vehicleName], ["Scheduled", scheduledTime], ["Route", `${routeDistance(delivery.route)} / ${routeDuration(delivery.route)}`]].map(([label, value]) => <div className={summaryCellClass} key={label}><p className="text-xs font-medium text-slate-400">{label}</p><p className="mt-1 truncate text-sm font-semibold text-slate-800" title={value}>{value}</p></div>)}</div></header><div className="user-modal-scrollbar flex-1 overflow-y-auto px-5 py-5"><div className="grid gap-5 lg:grid-cols-[minmax(0,3fr)_minmax(320px,2fr)]"><div className="space-y-5"><section className={cardClass}><h3 className="text-base font-semibold text-slate-950">Delivery information</h3><div className="mt-4 grid gap-3"><div className="grid gap-3 sm:grid-cols-2"><DetailItem icon={CustomerIcon} label="Customer" value={delivery.customerName} /><DetailItem icon={PhoneIcon} label="Phone" value={formatPhone(delivery.customerPhone)} /></div><DetailItem icon={PickupIcon} label="Pickup address" value={delivery.pickupAddress} /><DetailItem icon={DestinationIcon} label="Drop-off address" value={delivery.deliveryAddress} /></div><div className="mt-4 flex flex-wrap gap-x-5 gap-y-1 border-t border-slate-100 pt-3 text-xs text-slate-400"><span>Created by <strong className="font-semibold text-slate-500">{delivery.createdBy}</strong></span><span>Created {formatDateTime(delivery.createdAt)}</span><span>Updated {formatDateTime(delivery.updatedAt)}</span></div></section><section className={cardClass}><div className="flex flex-wrap items-center justify-between gap-3"><div><h3 className="text-base font-semibold text-slate-950">Route information</h3><p className="mt-1 text-sm text-slate-500">{routeDistance(delivery.route)} · {routeDuration(delivery.route)}</p></div>{delivery.route?.maps_url ? <SecondaryButton className={secondaryPurpleButtonClass} onClick={() => window.open(delivery.route?.maps_url ?? "", "_blank", "noopener,noreferrer")} type="button"><RouteIcon aria-hidden className="mr-2" size={15} weight="bold" />View Route</SecondaryButton> : null}</div>{delivery.route ? <div className="mt-5 grid gap-4"><div className="relative grid gap-5 pl-8 before:absolute before:bottom-7 before:left-[11px] before:top-7 before:w-px before:bg-purple-100"><div className="relative"><span className="absolute -left-8 top-1 grid h-6 w-6 place-items-center rounded-full border-2 border-purple-500 bg-white"><span className="h-2 w-2 rounded-full bg-purple-500" /></span><p className="text-xs font-medium text-slate-400">Pickup</p><p className="mt-1 text-sm font-semibold leading-6 text-slate-800">{routeOrigin}</p></div><div className="relative"><span className="absolute -left-8 top-1 grid h-6 w-6 place-items-center rounded-full bg-purple-600 text-white"><DestinationIcon aria-hidden size={13} weight="bold" /></span><p className="text-xs font-medium text-slate-400">Destination</p><p className="mt-1 text-sm font-semibold leading-6 text-slate-800">{routeDestination}</p></div></div></div> : <div className="mt-4 rounded-2xl border border-dashed border-slate-200 p-4 text-sm text-slate-500">No generated route is connected to this delivery yet.</div>}</section><section className="rounded-[20px] border border-purple-100/90 bg-white p-5 shadow-[0_1px_2px_rgba(15,23,42,0.04),0_10px_30px_rgba(139,92,246,0.08)]"><div className="flex gap-3"><span className="grid h-10 w-10 shrink-0 place-items-center rounded-2xl bg-purple-50 text-purple-600 ring-1 ring-purple-100"><NotesIcon aria-hidden size={18} weight="bold" /></span><div><h3 className="text-base font-semibold text-slate-950">Delivery notes</h3><p className="mt-2 text-sm leading-6 text-slate-600">{delivery.notes || "No delivery notes recorded."}</p></div></div></section></div><div className="space-y-5"><section className={accentCardClass}><div className="flex items-center gap-2"><span className="grid h-9 w-9 place-items-center rounded-xl bg-purple-50 text-purple-600 ring-1 ring-purple-100"><VehicleIcon aria-hidden size={17} weight="bold" /></span><h3 className="text-base font-semibold text-slate-950">Operational assignment</h3></div><div className="mt-4 grid gap-3 sm:grid-cols-2 lg:grid-cols-1 xl:grid-cols-2">{assignmentFields.map((field) => <div className={`rounded-2xl border border-purple-100/60 bg-purple-50/30 px-3 py-2.5 ${field.wide ? "md:col-span-2 lg:col-span-1 xl:col-span-2" : ""}`} key={field.label}><p className="text-xs font-medium text-slate-400">{field.label}</p><p className={`mt-1 text-sm font-semibold leading-5 text-slate-800 ${field.truncate ? "truncate" : ""}`} title={field.value}>{field.value}</p></div>)}</div></section><section className={cardClass}><div className="flex items-center gap-2"><span className="grid h-9 w-9 place-items-center rounded-xl bg-purple-50 text-purple-600 ring-1 ring-purple-100"><ActivityIcon aria-hidden size={17} weight="bold" /></span><h3 className="text-base font-semibold text-slate-950">Status history</h3></div>{delivery.history.length ? <div className="mt-5 space-y-0">{delivery.history.slice(0, 8).map((row, index) => { const status = normalizeStatus(historyValue(row, ["status", "new_status"]) ?? "pending"); const timestamp = historyValue(row, ["created_at", "changed_at", "updated_at"]); const changedBy = historyValue(row, ["changed_by", "updated_by", "created_by"]); const notes = historyValue(row, ["notes", "note", "comment"]); return <div className="relative pb-5 pl-8 last:pb-0 before:absolute before:bottom-0 before:left-[9px] before:top-6 before:w-px before:bg-slate-100 last:before:hidden" key={`${timestamp}-${index}`}><span className="absolute left-0 top-1 grid h-5 w-5 place-items-center rounded-full border-2 border-purple-500 bg-white"><span className="h-1.5 w-1.5 rounded-full bg-purple-500" /></span><div className="flex flex-wrap items-center justify-between gap-2"><StatusBadge status={status} /><span className="text-xs text-slate-400">{formatDateTime(timestamp)}</span></div>{changedBy ? <p className="mt-2 text-xs text-slate-500">Changed by {changedBy}</p> : null}{notes ? <p className="mt-2 rounded-xl border border-purple-100/60 bg-purple-50/30 px-3 py-2 text-xs leading-5 text-slate-600">{notes}</p> : null}</div>; })}</div> : <div className="mt-5 rounded-2xl border border-dashed border-slate-200 p-5 text-center"><span className="mx-auto grid h-11 w-11 place-items-center rounded-full bg-purple-50 text-purple-600"><ActivityIcon aria-hidden size={20} weight="bold" /></span><h4 className="mt-3 font-semibold text-slate-900">No status history yet</h4><p className="mt-1 text-sm leading-6 text-slate-500">Status changes will appear here as this delivery moves through operations.</p></div>}</section></div></div></div></div></div></div>;
}

