  function handleFormChange(field: keyof FormState, value: string) { setForm((current) => { if (field === "pickupAddress") return { ...current, pickupAddress: value, pickupPlaceId: "", pickupLatitude: "", pickupLongitude: "" }; if (field === "deliveryAddress") return { ...current, deliveryAddress: value, deliveryPlaceId: "", deliveryLatitude: "", deliveryLongitude: "" }; return { ...current, [field]: value }; }); }
  function handlePlace(field: "pickupAddress" | "deliveryAddress", place: SelectedPlace) { setForm((current) => field === "pickupAddress" ? { ...current, pickupAddress: place.formattedAddress, pickupPlaceId: place.placeId, pickupLatitude: place.latitude.toString(), pickupLongitude: place.longitude.toString() } : { ...current, deliveryAddress: place.formattedAddress, deliveryPlaceId: place.placeId, deliveryLatitude: place.latitude.toString(), deliveryLongitude: place.longitude.toString() }); }
  async function submit(event: FormEvent<HTMLFormElement>) { event.preventDefault(); setSaving(true); setError(""); const optionalNumber = (value: string) => value.trim() ? Number(value) : null; const delivery = { delivery_number: form.deliveryNumber.trim(), customer_name: form.customerName.trim(), customer_phone: form.customerPhone.trim() || null, pickup_address: form.pickupAddress.trim(), pickup_place_id: form.pickupPlaceId.trim() || null, pickup_latitude: optionalNumber(form.pickupLatitude), pickup_longitude: optionalNumber(form.pickupLongitude), delivery_address: form.deliveryAddress.trim(), delivery_place_id: form.deliveryPlaceId.trim() || null, delivery_latitude: optionalNumber(form.deliveryLatitude), delivery_longitude: optionalNumber(form.deliveryLongitude), assigned_driver_id: form.driverId || null, assigned_vehicle_id: form.vehicleId || null, status: form.status, priority: form.priority, notes: form.notes.trim() || null }; try { await fetchAdministratorJson("/api/admin/deliveries", { method: editing ? "PATCH" : "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify(editing ? { delivery_id: editing.id, delivery } : { delivery }) }); await loadData(); notify.success(editing ? "Delivery updated successfully." : "Delivery created successfully."); setModalOpen(false); setEditing(null); setForm(emptyForm); } catch (caught) { setError(caught instanceof Error ? caught.message : "Unable to save delivery."); } finally { setSaving(false); } }
